Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string targetWord, line, word;
    int count = 0;

    // Read the target word from user input
    std::cout << "Enter the target word: ";
    std::cin >> targetWord;

    // Open the input file
    std::ifstream inputFile("input.txt");

    // Check if the file is open, otherwise display an error message
    if (!inputFile.is_open()) {
        std::cerr << "Error opening the file" << std::endl;
        return 1;
    }

    // Read the file line by line
    while (std::getline(inputFile, line)) {
        // Reset the word variable for each line
        word = "";

        // Go through each character in the line
        for (char c : line) {
            // If the character is not a space or a tab, add it to the word
            if (c != ' ' && c != '\t') {
                word += c;
            } else {
                // If the current word matches the target word, increment the counter
                if (word == targetWord) {
                    ++count;
                }

                // Reset the word variable after processing spaces and tabs
                word = "";
            }
        }

        // Check if the last word in the line matches the target word
        if (word == targetWord) {
            ++count;
        }
    }

    // Close the input file
    inputFile.close();

    // Display the result
    std::cout << "The word '" << targetWord << "' occurred " << count << " times in the file." << std::endl;

    return 0;
}
```

To use this program, create a text file named `input.txt` in the same directory as the compiled executable. Then compile and run the program, entering the desired target word when prompted.

Please note that this program does not handle case sensitivity or punctuation. You can modify the code to include these features if needed.
